option.value:
services:
  postgres:
    image: postgres:16-alpine
    restart: unless-stopped
    command: ["postgres", "-p", "${POSTGRES_CONTAINER_PORT:-5432}"]
    environment:
      POSTGRES_DB: ${POSTGRES_DB:-leafsheets}
      POSTGRES_USER: ${POSTGRES_USER:-leafsheets}
      POSTGRES_PASSWORD: ${POSTGRES_PASSWORD:-leafsheets_dev_password}
    ports:
      - "${POSTGRES_HOST_PORT:-5432}:${POSTGRES_CONTAINER_PORT:-5432}"
    volumes:
      - pg_data:/var/lib/postgresql/data
    healthcheck:
      test: ["CMD-SHELL", "pg_isready -U ${POSTGRES_USER:-leafsheets} -p ${POSTGRES_CONTAINER_PORT:-5432}"]
      interval: 10s
      timeout: 5s
      retries: 10

  backend:
    build:
      context: ./backend
    restart: unless-stopped
    depends_on:
      postgres:
        condition: service_healthy
    environment:
      NODE_ENV: production
      PORT: ${BACKEND_CONTAINER_PORT:-5000}
      DATABASE_URL: postgresql://${POSTGRES_USER:-leafsheets}:${POSTGRES_PASSWORD:-leafsheets_dev_password}@postgres:${POSTGRES_CONTAINER_PORT:-5432}/${POSTGRES_DB:-leafsheets}?schema=public
      BACKEND_URL: ${BACKEND_PUBLIC_URL:-http://localhost}
      FRONTEND_URL: ${FRONTEND_PUBLIC_URL:-http://localhost}
      ADMIN_JWT_SECRET: ${BACKEND_ADMIN_JWT_SECRET}
      JWT_EXPIRES_IN: ${BACKEND_JWT_EXPIRES_IN:-7d}
      BACKEND_ADMIN_EMAIL: ${BACKEND_ADMIN_EMAIL:-admin@admin.com}
      BACKEND_ADMIN_USERNAME: ${BACKEND_ADMIN_USERNAME:-admin}
      BACKEND_ADMIN_PASSWORD: ${BACKEND_ADMIN_PASSWORD:-adminPass123}
      SSLCOMMERZ_STORE_ID: ${SSLCOMMERZ_STORE_ID}
      SSLCOMMERZ_STORE_PASSWORD: ${SSLCOMMERZ_STORE_PASSWORD}
      SSLCOMMERZ_IS_LIVE: ${SSLCOMMERZ_IS_LIVE:-false}
      SSLCOMMERZ_BASE_URL: ${SSLCOMMERZ_BASE_URL:-}
      SSLCOMMERZ_SESSION_API_URL: ${SSLCOMMERZ_SESSION_API_URL:-}
      SSLCOMMERZ_VALIDATION_API_URL: ${SSLCOMMERZ_VALIDATION_API_URL:-}
    ports:
      - "${BACKEND_HOST_PORT:-5000}:${BACKEND_CONTAINER_PORT:-5000}"
    volumes:
      - backend_uploads:/app/uploads
      - backend_downloads:/app/public/downloads

  frontend:
    build:
      context: ./frontend
      args:
        NEXT_PUBLIC_API_URL: ${NEXT_PUBLIC_API_URL:-/api}
        BACKEND_SERVER_URL: http://backend:${BACKEND_CONTAINER_PORT:-5000}
        NEXT_PUBLIC_FIREBASE_API_KEY: ${NEXT_PUBLIC_FIREBASE_API_KEY}
        NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN: ${NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN}
        NEXT_PUBLIC_FIREBASE_PROJECT_ID: ${NEXT_PUBLIC_FIREBASE_PROJECT_ID}
        NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET: ${NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET}
        NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID: ${NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID}
        NEXT_PUBLIC_FIREBASE_APP_ID: ${NEXT_PUBLIC_FIREBASE_APP_ID}
        NEXT_PUBLIC_FIREBASE_MEASUREMENT_ID: ${NEXT_PUBLIC_FIREBASE_MEASUREMENT_ID}
    restart: unless-stopped
    depends_on:
      - backend
    environment:
      NODE_ENV: production
      PORT: ${FRONTEND_CONTAINER_PORT:-3000}
      NEXT_PUBLIC_API_URL: ${NEXT_PUBLIC_API_URL:-/api}
      BACKEND_SERVER_URL: http://backend:${BACKEND_CONTAINER_PORT:-5000}
    command: ["sh", "-c", "npm run start -- -p ${FRONTEND_CONTAINER_PORT:-3000}"]
    ports:
      - "${FRONTEND_HOST_PORT:-3000}:${FRONTEND_CONTAINER_PORT:-3000}"

  nginx:
    image: nginx:1.27-alpine
    restart: unless-stopped
    depends_on:
      - frontend
      - backend
    ports:
      - "${NGINX_HOST_PORT:-80}:${NGINX_CONTAINER_PORT:-80}"
    environment:
      NGINX_CONTAINER_PORT: ${NGINX_CONTAINER_PORT:-80}
      BACKEND_CONTAINER_PORT: ${BACKEND_CONTAINER_PORT:-5000}
      FRONTEND_CONTAINER_PORT: ${FRONTEND_CONTAINER_PORT:-3000}
    volumes:
      - ./nginx/default.conf.template:/etc/nginx/templates/default.conf.template:ro

volumes:
  pg_data:
  backend_uploads:
  backend_downloads:

services:
  postgres:
    image: postgres:16-alpine
    restart: unless-stopped
    command: ["postgres", "-p", "${POSTGRES_CONTAINER_PORT:-5432}"]
    environment:
      POSTGRES_DB: ${POSTGRES_DB:-leafsheets}
      POSTGRES_USER: ${POSTGRES_USER:-leafsheets}
      POSTGRES_PASSWORD: ${POSTGRES_PASSWORD:-leafsheets_dev_password}
    ports:
      - "${POSTGRES_HOST_PORT:-5432}:${POSTGRES_CONTAINER_PORT:-5432}"
    volumes:
      - pg_data:/var/lib/postgresql/data
    healthcheck:
      test: ["CMD-SHELL", "pg_isready -U ${POSTGRES_USER:-leafsheets} -p ${POSTGRES_CONTAINER_PORT:-5432}"]
      interval: 10s
      timeout: 5s
      retries: 10

  backend:
    build:
      context: ./backend
    restart: unless-stopped
    depends_on:
      postgres:
        condition: service_healthy
    environment:
      NODE_ENV: production
      PORT: ${BACKEND_CONTAINER_PORT:-5000}
      DATABASE_URL: postgresql://${POSTGRES_USER:-leafsheets}:${POSTGRES_PASSWORD:-leafsheets_dev_password}@postgres:${POSTGRES_CONTAINER_PORT:-5432}/${POSTGRES_DB:-leafsheets}?schema=public
      BACKEND_URL: ${BACKEND_PUBLIC_URL:-http://localhost}
      FRONTEND_URL: ${FRONTEND_PUBLIC_URL:-http://localhost}
      ADMIN_JWT_SECRET: ${BACKEND_ADMIN_JWT_SECRET}
      JWT_EXPIRES_IN: ${BACKEND_JWT_EXPIRES_IN:-7d}
      BACKEND_ADMIN_EMAIL: ${BACKEND_ADMIN_EMAIL:-admin@admin.com}
      BACKEND_ADMIN_USERNAME: ${BACKEND_ADMIN_USERNAME:-admin}
      BACKEND_ADMIN_PASSWORD: ${BACKEND_ADMIN_PASSWORD:-adminPass123}
      SSLCOMMERZ_STORE_ID: ${SSLCOMMERZ_STORE_ID}
      SSLCOMMERZ_STORE_PASSWORD: ${SSLCOMMERZ_STORE_PASSWORD}
      SSLCOMMERZ_IS_LIVE: ${SSLCOMMERZ_IS_LIVE:-false}
      SSLCOMMERZ_BASE_URL: ${SSLCOMMERZ_BASE_URL:-}
      SSLCOMMERZ_SESSION_API_URL: ${SSLCOMMERZ_SESSION_API_URL:-}
      SSLCOMMERZ_VALIDATION_API_URL: ${SSLCOMMERZ_VALIDATION_API_URL:-}
    ports:
      - "${BACKEND_HOST_PORT:-5000}:${BACKEND_CONTAINER_PORT:-5000}"
    volumes:
      - backend_uploads:/app/uploads
      - backend_downloads:/app/public/downloads

  frontend:
    build:
      context: ./frontend
      dockerfile: Dockerfile
      args:
        NEXT_PUBLIC_API_URL: ${NEXT_PUBLIC_API_URL:-/api}
        BACKEND_SERVER_URL: http://backend:${BACKEND_CONTAINER_PORT:-5000}
        NEXT_PUBLIC_FIREBASE_API_KEY: ${NEXT_PUBLIC_FIREBASE_API_KEY}
        NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN: ${NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN}
        NEXT_PUBLIC_FIREBASE_PROJECT_ID: ${NEXT_PUBLIC_FIREBASE_PROJECT_ID}
        NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET: ${NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET}
        NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID: ${NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID}
        NEXT_PUBLIC_FIREBASE_APP_ID: ${NEXT_PUBLIC_FIREBASE_APP_ID}
        NEXT_PUBLIC_FIREBASE_MEASUREMENT_ID: ${NEXT_PUBLIC_FIREBASE_MEASUREMENT_ID}
      # Force rebuild by using cache-busting timestamp
      cache_from: []
    restart: unless-stopped
    depends_on:
      - backend
    environment:
      NODE_ENV: production
      PORT: ${FRONTEND_CONTAINER_PORT:-3000}
      NEXT_PUBLIC_API_URL: ${NEXT_PUBLIC_API_URL:-/api}
      BACKEND_SERVER_URL: http://backend:${BACKEND_CONTAINER_PORT:-5000}
    command: ["sh", "-c", "rm -rf .next && npm run start -- -p ${FRONTEND_CONTAINER_PORT:-3000}"]
    ports:
      - "${FRONTEND_HOST_PORT:-3000}:${FRONTEND_CONTAINER_PORT:-3000}"
    volumes:
      # Clear Next.js cache on restart
      - /app/.next

  nginx:
    image: nginx:1.27-alpine
    restart: unless-stopped
    depends_on:
      - frontend
      - backend
    ports:
      - "${NGINX_HOST_PORT:-80}:${NGINX_CONTAINER_PORT:-80}"
    environment:
      NGINX_CONTAINER_PORT: ${NGINX_CONTAINER_PORT:-80}
      BACKEND_CONTAINER_PORT: ${BACKEND_CONTAINER_PORT:-5000}
      FRONTEND_CONTAINER_PORT: ${FRONTEND_CONTAINER_PORT:-3000}
    volumes:
      - ./nginx/default.conf.template:/etc/nginx/templates/default.conf.template:ro

volumes:
  pg_data:
  backend_uploads:
  backend_downloads:

eclare module 'prisma/config' {
  export function defineConfig<T>(config: T): T;
}

declare module 'prisma/config' {
  export function defineConfig<T>(config: T): T;
}
